}

def parse_grant_date(s):
    if not s:
        return None
    s_low = s.lower()
    # find year
    myear = re.search(r'(20\d{2})', s)
    if not myear:
        return None
    year = int(myear.group(1))
    # find month name
    mmonth = re.search(r'(?:(jan|feb|mar|apr|may|jun|jul|aug|sep|sept|oct|nov|dec)[a-z]*)', s_low)
    if mmonth:
