        continue
    year, month = parsed
    if year == 2019 and month is not None and month >= 7 and month <= 12:
        filtered.append(rec)

# Aggregate counts per level-4 CPC symbol per filing year
counts = defaultdict(lambda: defaultdict(int))
for rec in filtered:
    cpc_field = rec.get('cpc')
